import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Instalowanie modów","description":"Przewodnik krok po kroku o tym, jak zainstalować mody do Fabric.","frontmatter":{"title":"Instalowanie modów","description":"Przewodnik krok po kroku o tym, jak zainstalować mody do Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pl_pl/1.21.10/players/installing-mods.md","filePath":"versions/1.21.10/translated/pl_pl/players/installing-mods.md","lastUpdated":1766682904000}`);var s={name:`pl_pl/1.21.10/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalowanie modów <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalowanie modów”">​</a></h1><p>Ten przewodnik pokaże ci, jak zainstalować mody do Fabric dla oficjalnego launchera Minecrafta.</p><p>W przypadku innych launcherów należy zapoznać się z ich dokumentacją.</p><h2 id="1-download-the-mod" tabindex="-1">1. Pobierz moda <a class="header-anchor" href="#1-download-the-mod" aria-label="Permalink to “1. Pobierz moda”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Mody należy pobierać wyłącznie z zaufanych źródeł. Po więcej informacji sprawdź przewodnik na temat <a href="./finding-mods">znajdowania wiarygodnych modów</a>.</p></div><p>Większość modów wymaga również Fabric API, które można pobrać z <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> lub <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Podczas pobierania modów upewnij się, że:</p><ul><li>Działają na wersji Minecrafta, na której chcesz grać. Dla przykładu mod działający na wersji 1.20 może nie działać na wersji 1.20.2.</li><li>Są przeznaczone dla Fabric, a nie innego mod loadera.</li><li>Są przeznaczone dla właściwej edycji Minecrafta (Java Edition).</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. Przenieś moda do folderu <code>mods</code> <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. Przenieś moda do folderu mods”">​</a></h2><p>Folder <code>mods</code> znajdziesz w następujących lokalizacjach dla poszczególnych systemów operacyjnych.</p><p>Zazwyczaj możesz wkleić te ścieżki do paska adresu swojego eksploratora plików, aby szybko przejść do folderu.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Po znalezieniu folderu <code>mods</code>, przenieś do niego pliki <code>.jar</code> modów.</p><p><img src="/assets/players/installing-mods.png" alt="Zainstalowane mody w folderze mods" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. I to tyle! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. I to tyle!”">​</a></h2><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher Minecrafta z wybranym profilem Fabric" loading="lazy"></p><p>Po przeniesieniu modów do folderu <code>mods</code> możesz otworzyć launcher Minecrafta i wybrać z rozwijanej listy w lewym dolnym rogu profil Fabric, a następnie zacząć grać!</p><h2 id="troubleshooting" tabindex="-1">Rozwiązywanie problemów <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Rozwiązywanie problemów”">​</a></h2><p>Jeśli napotkasz jakiś problem podczas korzystania z tego przewodnika, możesz poprosić o pomoc na <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discordzie Fabric</a> na kanale <code>#player-support</code>.</p><p>Możesz również spróbować samodzielnie rozwiązać problem, czytając strony poświęcone rozwiązywaniu problemów:</p><ul><li><a href="./troubleshooting/crash-reports">Raporty awarii</a></li><li><a href="./troubleshooting/uploading-logs">Przesyłanie logów</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};